const crypto = require('crypto');

/**
 * Generates a cryptographically secure random token for password reset links.
 * 
 * @param {number} length - The length of the token in bytes (default: 32, which produces a 64-character hex string)
 * @param {string} encoding - The encoding format for the token ('hex', 'base64url', 'base64') (default: 'base64url')
 * @param {number} expiresInMinutes - Token expiry time in minutes (default: 30)
 * @returns {Promise<{token: string, hash: string, expiresAt: Date}>} The plain token (to send to user), its hash (to store in DB), and expiry date
 */
async function generatePasswordResetToken(length = 32, encoding = 'base64url', expiresInMinutes = 30) {
    if (length < 32) {
        throw new Error('Token length must be at least 32 bytes for adequate security.');
    }

    const validEncodings = ['hex', 'base64url', 'base64'];
    if (!validEncodings.includes(encoding)) {
        throw new Error(`Invalid encoding. Must be one of: ${validEncodings.join(', ')}`);
    }

    if (expiresInMinutes < 1 || expiresInMinutes > 1440) {
        throw new Error('Expiry time must be between 1 and 1440 minutes (24 hours).');
    }

    return new Promise((resolve, reject) => {
        crypto.randomBytes(length, (err, buffer) => {
            if (err) {
                reject(new Error(`Failed to generate secure random bytes: ${err.message}`));
                return;
            }

            // The plain token to be sent to the user (e.g., in a reset link)
            const token = buffer.toString(encoding);

            // Hash the token using SHA-256 with a per-token salt for storage in the database.
            // We never store the plain token — only the hash.
            // This way, even if the database is compromised, tokens cannot be used directly.
            const salt = crypto.randomBytes(16).toString('hex');
            const hash = crypto
                .createHmac('sha256', salt)
                .update(token)
                .digest('hex');

            const tokenHash = `${salt}:${hash}`;

            // Calculate expiration date
            const expiresAt = new Date(Date.now() + expiresInMinutes * 60 * 1000);

            resolve({
                token,       // Send this to the user via email (in the reset URL)
                hash: tokenHash,  // Store this in the database
                expiresAt    // Store this in the database alongside the hash
            });
        });
    });
}

/**
 * Verifies a password reset token against its stored hash.
 * 
 * @param {string} token - The plain token received from the user
 * @param {string} storedHash - The hash stored in the database (format: "salt:hash")
 * @param {Date|string} expiresAt - The expiration date stored in the database
 * @returns {boolean} Whether the token is valid and not expired
 */
function verifyPasswordResetToken(token, storedHash, expiresAt) {
    if (!token || !storedHash || !expiresAt) {
        return false;
    }

    // Check expiration first (fail fast)
    const expirationDate = new Date(expiresAt);
    if (Date.now() > expirationDate.getTime()) {
        return false;
    }

    // Parse the stored hash
    const parts = storedHash.split(':');
    if (parts.length !== 2) {
        return false;
    }

    const [salt, originalHash] = parts;

    // Recompute the hash with the same salt
    const computedHash = crypto
        .createHmac('sha256', salt)
        .update(token)
        .digest('hex');

    // Use timing-safe comparison to prevent timing attacks
    try {
        const originalBuffer = Buffer.from(originalHash, 'hex');
        const computedBuffer = Buffer.from(computedHash, 'hex');

        if (originalBuffer.length !== computedBuffer.length) {
            return false;
        }

        return crypto.timingSafeEqual(originalBuffer, computedBuffer);
    } catch {
        return false;
    }
}

